arguments.argument:
if global.gamePaused=false
{
  vaultMaze[0]=string_char_at(global.gameVaultProg,1)
  vaultMaze[1]=string_char_at(global.gameVaultProg,2)
  vaultMaze[2]=string_char_at(global.gameVaultProg,3)
  vaultMaze[3]=string_char_at(global.gameVaultProg,4)
  
  //Key timer
  if global.tempAction[2]>0 {global.tempAction[2]-=1}
  haveKey=0
  for(i=0;i<4;i+=1) //Check for key
  {
    if vaultMaze[i]="1" {haveKey=1}
  }
  if haveKey=1 and global.tempAction[2]<=0 //Time runs out
  {
    var tWhichKey;
    tWhichKey=1
    for(i=0;i<4;i+=1)
    {
      if vaultMaze[i]="1" {break;}
      tWhichKey+=1
    }
    var tNewString;
    tNewString=string_delete(global.gameVaultProg,tWhichKey,1)
    tNewString=string_insert("0",tNewString,tWhichKey)
    global.gameVaultProg=tNewString
    
    global.tempAction[2]=0
  }
  
  //Shift time
  if oPlayer1.state=oPlayer1.LOOKING_UP {global.tempAction[1]-=12}
  else {global.tempAction[1]-=1}
  if global.tempAction[1]<=0 //Shift rooms
  {
    playSound(global.snd_HardHit1,0,0.98,7000)
    tSrnInv=instance_create(0,0,oScreenInvert); tSrnInv.invertTime=20
    
    global.vaultRooms+=1
    if global.vaultRooms=5 {global.vaultRooms=1}
    if room=rVault_R_A
    {
      if global.vaultRooms=1 or global.vaultRooms=3
      {
        with (GID(257026)) {toRoom=rVault_R_B}
        with (GID(257033)) {toRoom=rVault_R_B}
        with (GID(257034)) {toRoom=rVault_R_B}
        with (GID(257035)) {toRoom=rVault_R_B}
        with (GID(257036)) {toRoom=rVault_R_B}
        with (GID(257037)) {toRoom=rVault_R_B}
        with (GID(257038)) {toRoom=rVault_R_D}
      }
      else if global.vaultRooms=2 or global.vaultRooms=4
      {
        with (GID(257026)) {toRoom=rVault_R_D}
        with (GID(257033)) {toRoom=rVault_R_D}
        with (GID(257034)) {toRoom=rVault_R_D}
        with (GID(257035)) {toRoom=rVault_R_D}
        with (GID(257036)) {toRoom=rVault_R_D}
        with (GID(257037)) {toRoom=rVault_R_D}
        with (GID(257038)) {toRoom=rVault_R_B}
      }
    }
    else if room=rVault_R_B
    {
      if global.vaultRooms=1 or global.vaultRooms=3
      {
        with (GID(257039)) {toRoom=rVault_R_A}
        with (GID(257040)) {toRoom=rVault_R_A}
        with (GID(257041)) {toRoom=rVault_R_A}
        with (GID(257042)) {toRoom=rVault_R_A}
        with (GID(257043)) {toRoom=rVault_R_A}
        with (GID(257044)) {toRoom=rVault_R_A}
        with (GID(257045)) {toRoom=rVault_R_C}
      }
      else if global.vaultRooms=2 or global.vaultRooms=4
      {
        with (GID(257039)) {toRoom=rVault_R_C}
        with (GID(257040)) {toRoom=rVault_R_C}
        with (GID(257041)) {toRoom=rVault_R_C}
        with (GID(257042)) {toRoom=rVault_R_C}
        with (GID(257043)) {toRoom=rVault_R_C}
        with (GID(257044)) {toRoom=rVault_R_C}
        with (GID(257045)) {toRoom=rVault_R_A}
      }
    }
    else if room=rVault_R_C
    {
      if global.vaultRooms=1 or global.vaultRooms=3
      {
        with (GID(257046)) {toRoom=rVault_R_D}
        with (GID(257047)) {toRoom=rVault_R_D}
        with (GID(257063)) {toRoom=rVault_R_D}
        with (GID(257064)) {toRoom=rVault_R_D}
        with (GID(257065)) {toRoom=rVault_R_D}
        with (GID(257066)) {toRoom=rVault_R_D}
        with (GID(257067)) {toRoom=rVault_R_B}
      }
      else if global.vaultRooms=2 or global.vaultRooms=4
      {
        with (GID(257046)) {toRoom=rVault_R_B}
        with (GID(257047)) {toRoom=rVault_R_B}
        with (GID(257063)) {toRoom=rVault_R_B}
