      }
    }
    else if room=rVault_R_D
    {
      if global.vaultRooms=1 or global.vaultRooms=3
      {
        with (GID(257068)) {toRoom=rVault_R_C}
        with (GID(257069)) {toRoom=rVault_R_C}
        with (GID(257070)) {toRoom=rVault_R_C}
        with (GID(257071)) {toRoom=rVault_R_C}
        with (GID(257072)) {toRoom=rVault_R_C}
        with (GID(257073)) {toRoom=rVault_R_C}
        with (GID(257074)) {toRoom=rVault_R_A}
      }
      else if global.vaultRooms=2 or global.vaultRooms=4
      {
        with (GID(257068)) {toRoom=rVault_R_A}
        with (GID(257069)) {toRoom=rVault_R_A}
        with (GID(257070)) {toRoom=rVault_R_A}
        with (GID(257071)) {toRoom=rVault_R_A}
        with (GID(257072)) {toRoom=rVault_R_A}
        with (GID(257073)) {toRoom=rVault_R_A}
        with (GID(257074)) {toRoom=rVault_R_C}
      }
    }
    global.tempAction[1]=1500
  }
}
